import { Type } from "@google/genai";
import { generateWithSchema } from '../geminiClient';
import { GeneratorOptions, ClockReadingData } from '../../types';
import { getMathPrompt } from './prompts';

export const generateClockReadingFromAI = async (options: GeneratorOptions): Promise<ClockReadingData[]> => {
    const { difficulty, worksheetCount, itemCount = 4, variant = 'analog-to-digital', studentContext } = options;

    const variantDesc = {
        'analog-to-digital': 'Analog saatten dijital saate dönüşüm.',
        'digital-to-analog': 'Dijital saati analog kadran üzerinde çizme.',
        'verbal-match': 'Sözel ifadeleri (çeyrek var, buçuk gibi) saatle eşleştirme.',
        'elapsed-time': 'Zaman aritmetiği ve geçen süre problemleri.'
    }[variant] || 'Zaman algısı';

    const rule = `
    [GÖREV]: Saat Okuma ve Zaman Algısı Etkinliği Üret.
    ZORLUK: ${difficulty}
    VARYANT: ${variantDesc}
    ADET: Sayfa başına ${itemCount} görev.

    KURALLAR:
    1. Başlangıç: Sadece tam ve yarım saatler.
    2. Orta: 5 dakikalık dilimler ve sözel ifadeler.
    3. Zor: 1 dakikalık hassasiyet ve 24 saatlik format.
    4. Uzman: Karmaşık zaman problemleri (Örn: 2 saat 15 dk sonra saat kaç olur?).

    Her bir 'clock' nesnesi için 'verbalTime' alanına Türkçe sözel okunuşunu yaz (örn: "Onu yirmi beş geçiyor").
    Problemlerde öğrencinin ilgi alanlarını kullan.
    `;

    const prompt = getMathPrompt("Zaman Algısı ve Saat Atölyesi", difficulty, rule, studentContext);

    const schema = {
        type: Type.ARRAY,
        items: {
            type: Type.OBJECT,
            properties: {
                title: { type: Type.STRING },
                instruction: { type: Type.STRING },
                pedagogicalNote: { type: Type.STRING },
                variant: { type: Type.STRING },
                clocks: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            id: { type: Type.STRING },
                            hour: { type: Type.INTEGER },
                            minute: { type: Type.INTEGER },
                            timeString: { type: Type.STRING },
                            verbalTime: { type: Type.STRING },
                            options: { type: Type.ARRAY, items: { type: Type.STRING } },
                            answer: { type: Type.STRING },
                            problemText: { type: Type.STRING, nullable: true }
                        },
                        required: ['id', 'hour', 'minute', 'timeString', 'answer']
                    }
                }
            },
            required: ['title', 'instruction', 'clocks']
        }
    };

    return await generateWithSchema(prompt, schema, 'gemini-3-flash-preview');
};

export const generateNumberLogicRiddlesFromAI = async (options: GeneratorOptions): Promise<any[]> => {
    const { 
        difficulty, 
        numberRange, 
        worksheetCount, 
        itemCount = 4, 
        studentContext,
        logicModel = 'identity',
        gridSize = 3,
        showSumTarget = true
    } = options;

    const modelDesc = {
        'identity': 'Sayı Kimliği: Sayının basamak değerleri, tek/çift durumu ve komşuluk ilişkilerine odaklan.',
        'exclusion': 'Eleme Mantığı: "X değildir", "Şundan küçüktür ama şu değildir" gibi dışlayıcı önermeler kullan.',
        'sequence': 'Dizi/Örüntü: Sayının bir aritmetik dizideki yerini veya katlarını ipucu olarak ver.',
        'cryptarithmetic': 'Şifreleme: Sayıyı oluşturan rakamları sembollerle veya toplamsal bulmacalarla anlat.'
    }[logicModel];

    const rule = `
    [KESİN GÖREV]: Sayısal Muhakeme ve Mantık Bilmeceleri Üret.
    [ZORLUK SEVİYESİ]: ${difficulty}
    [SAYI EVRENİ]: ${numberRange || '1-50'}
    [MANTIK MODELİ]: ${modelDesc}
    [İPUCU SAYISI]: Her bir bilmece için TAM OLARAK ${gridSize} ADET bağımsız ipucu/önerme yaz. Ne eksik ne fazla!
    [SAYFA YAPISI]: Bir sayfada ${itemCount} adet bağımsız bilmece kutusu olsun.

    HESAPLAMA KURALLARI:
    1. Zorluk seviyesine göre sayıları seç: Başlangıç (1-10), Orta (1-50), Zor (1-100), Uzman (100-999).
    2. İpuçları birbirini desteklemeli ve tek bir doğru cevaba götürmeli.
    3. ${showSumTarget ? "'sumTarget' alanına, bu sayfadaki tüm doğru cevapların matematiksel toplamını yaz." : ""}

    JSON formatında döndür. Her bilmece için 'riddle' alanı ipuçlarının birleşimi olsun. 'options' alanında 4 seçenek ver.
    `;

    const prompt = getMathPrompt("Gelişmiş Sayısal Mantık Bilmeceleri", difficulty, rule, studentContext);

    const schema = {
        type: Type.ARRAY,
        items: {
            type: Type.OBJECT,
            properties: {
                title: { type: Type.STRING },
                instruction: { type: Type.STRING },
                pedagogicalNote: { type: Type.STRING },
                sumTarget: { type: Type.INTEGER },
                sumMessage: { type: Type.STRING },
                puzzles: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            riddle: { type: Type.STRING },
                            visualHint: { type: Type.STRING },
                            boxes: { type: Type.ARRAY, items: { type: Type.ARRAY, items: { type: Type.INTEGER } } },
                            options: { type: Type.ARRAY, items: { type: Type.STRING } },
                            answer: { type: Type.STRING },
                            answerValue: { type: Type.INTEGER }
                        },
                        required: ['riddle', 'boxes', 'options', 'answer', 'answerValue']
                    }
                }
            },
            required: ['title', 'puzzles']
        }
    };

    return await generateWithSchema(prompt, schema, 'gemini-3-flash-preview');
};

import { GeneratorOptions, NumberPatternData, NumberPyramidData, OddEvenSudokuData, KendokuData, MoneyCountingData, MathMemoryCardsData, ClockReadingData, RealLifeProblemData, MathPuzzleData, NumberLogicRiddleData } from '../../types';
import { shuffle, getRandomInt, getRandomItems, turkishAlphabet, generateSudokuGrid, generateLatinSquare, TR_VOCAB } from './helpers';

export const generateOfflineClockReading = async (options: GeneratorOptions): Promise<ClockReadingData[]> => {
    const { worksheetCount, difficulty, itemCount = 6, variant = 'analog-to-digital' } = options;
    const pages: ClockReadingData[] = [];

    for (let p = 0; p < worksheetCount; p++) {
        const clocks = [];
        for (let i = 0; i < itemCount; i++) {
            let hour = getRandomInt(1, 12);
            let minute = 0;

            // Pedagojik Sınıflandırma
            if (difficulty === 'Başlangıç') {
                minute = Math.random() > 0.5 ? 0 : 30;
            } else if (difficulty === 'Orta') {
                const step = [0, 15, 30, 45, 10, 20, 40, 50];
                minute = step[getRandomInt(0, step.length - 1)];
            } else if (difficulty === 'Zor') {
                minute = getRandomInt(0, 59);
            } else {
                minute = getRandomInt(0, 59);
                hour = getRandomInt(0, 23);
            }

            const timeString = `${hour.toString().padStart(2, '0')}:${minute.toString().padStart(2, '0')}`;

            // Seçenekler oluştur
            const distractors = new Set<string>();
            while (distractors.size < 3) {
                const dH = getRandomInt(1, 12).toString().padStart(2, '0');
                const dM = [0, 15, 30, 45][getRandomInt(0,3)].toString().padStart(2, '0');
                if (`${dH}:${dM}` !== timeString) distractors.add(`${dH}:${dM}`);
            }

            clocks.push({
                id: `clk-${p}-${i}`,
                hour,
                minute,
                timeString,
                options: shuffle([timeString, ...Array.from(distractors)]),
                answer: timeString
            });
        }

        pages.push({
            title: "Zaman Atölyesi: Saatleri Öğreniyorum",
            instruction: "Analog saatlerde gösterilen zamanı dijital kutucuklara yazın veya doğru seçeneği işaretleyin.",
            pedagogicalNote: "Görsel-uzamsal algı ve sayısal sembolizasyon becerilerini zaman kavramı üzerinden destekler.",
            variant: variant as any,
            clocks,
            settings: {
                showNumbers: true,
                is24Hour: difficulty === 'Uzman',
                showTicks: true,
                difficulty
            }
        });
    }
    return pages;
};

// SAYISAL MANTIK BİLMECELERİ (Gelişmiş Yerel Üretici)
export const generateOfflineNumberLogicRiddles = async (options: GeneratorOptions): Promise<NumberLogicRiddleData[]> => {
    const { worksheetCount, numberRange, difficulty, gridSize = 3, itemCount = 4 } = options;

    const [minRange, maxRange] = (numberRange || '1-50').split('-').map(Number);
    const pages: NumberLogicRiddleData[] = [];

    for (let p = 0; p < worksheetCount; p++) {
        const puzzles = [];
        let runningTotal = 0;

        for (let i = 0; i < itemCount; i++) {
            const targetNumber = getRandomInt(minRange, maxRange);
            const hints: string[] = [];

            // Dinamik İpucu Üretim Havuzu (gridSize kadar seçilecek)
            const potentialHints = [
                targetNumber % 2 === 0 ? "Ben bir çift sayıyım." : "Ben bir tek sayıyım.",
                targetNumber > (maxRange / 2) ? `${Math.floor(maxRange/2)}'den büyüğüm.` : `${Math.floor(maxRange/2)}'den küçüğüm.`,
                targetNumber > 9 ? `Onlar basamağım ${Math.floor(targetNumber/10)}'dir.` : "Tek basamaklı bir sayıyım.",
                targetNumber % 5 === 0 ? "5'in tam katıyım." : "5'e tam bölünmem.",
                targetNumber % 10 === 0 ? "Sonumda 0 rakamı var." : "Son rakamım 0 değil.",
                `Rakamlarım toplamı ${targetNumber.toString().split('').reduce((a,b)=>a+parseInt(b),0)}'dir.`,
                targetNumber < 100 ? `100'e olan uzaklığım ${100-targetNumber}'dir.` : "Üç basamaklıyım."
            ];

            // Kullanıcının istediği ipucu sayısı kadar rastgele ama tutarlı ipucu seç
            const selectedHints = shuffle(potentialHints).slice(0, gridSize);

            // Seçenek kutuları (Boxes) görsel doluluk için
            const boxes = Array.from({ length: 5 }, () => {
                const b = [getRandomInt(minRange, maxRange), getRandomInt(minRange, maxRange)];
                return b;
            });
            // Bir tanesine mutlaka doğru cevabı koy
            boxes[getRandomInt(0, 4)][getRandomInt(0, 1)] = targetNumber;

            const distractors = new Set<number>();
            while(distractors.size < 3) {
                const d = getRandomInt(minRange, maxRange);
                if (d !== targetNumber) distractors.add(d);
            }
            const allOptions = shuffle([targetNumber.toString(), ...Array.from(distractors).map(d => d.toString())]);
            const correctLetter = ['A', 'B', 'C', 'D'][allOptions.indexOf(targetNumber.toString())];

            puzzles.push({
                riddle: selectedHints.join(' '),
                boxes,
                options: allOptions,
                answer: `${correctLetter} - ${targetNumber}`,
                answerValue: targetNumber
            });

            runningTotal += targetNumber;
        }

        pages.push({
            title: "Sayısal Mantık Bilmeceleri",
            instruction: "İpuçlarını dikkatle oku, zihninde sayıyı canlandır ve doğru seçeneği işaretle!",
            pedagogicalNote: `Bu etkinlik, ${gridSize} aşamalı mantıksal çıkarım yapma, işleyen bellek ve sayı hissi becerilerini geliştirir.`,
            sumTarget: runningTotal,
            sumMessage: `Kontrol Paneli: Tüm doğru cevapları topladığında ${runningTotal} sayısına ulaşmalısın.`,
            puzzles
        });
    }

    return pages;
};

