                        icon="fa-list-ol" 
                    />
                </div>
            );
        }

        if (activity.id === ActivityType.VISUAL_ODD_ONE_OUT) {
            return (
                <div className="space-y-5">
                    <CompactSelect 
                        label="İçerik Mimarisi" 
                        value={options.visualType} 
