export const generateClockReadingFromAI = async (options: GeneratorOptions): Promise<ClockReadingData[]> => {
    const { difficulty, worksheetCount, itemCount = 4, variant = 'analog-to-digital', studentContext, is24Hour, showNumbers, showTicks } = options;

    const variantDesc = {
        'analog-to-digital': 'Analog saatten dijital saate dönüşüm.',
        'digital-to-analog': 'Dijital saati analog kadran üzerinde çizme.',
        'verbal-match': 'Sözel ifadeleri (çeyrek var, buçuk gibi) saatle eşleştirme.',
        'elapsed-time': 'Zaman aritmetiği ve geçen süre problemleri.'
    }[variant] || 'Zaman okuma';

    const rule = `
    [GÖREV]: Profesyonel Seviye Saat Okuma ve Zaman Algısı Etkinliği Üret.
    ZORLUK SEVİYESİ: ${difficulty}
    VARYANT: ${variantDesc}
    ADET: Sayfa başına ${itemCount} görev.

    GÖRSEL AYARLAR (Bu ayarlar son kullanıcıya gösterilecek kadran stilini belirler):
    - Format: ${is24Hour ? '24 Saat (Örn: 14:30)' : '12 Saat (Örn: 02:30)'}
    - Saat Rakamları: ${showNumbers ? 'GÖRÜNÜR' : 'GİZLİ (Sadece çizgiler)'}
    - Dakika Çizgileri: ${showTicks ? 'GÖRÜNÜR' : 'GİZLİ'}

    ÖZEL TALİMATLAR:
    1. Eğer varyant 'elapsed-time' ise: 'problemText' alanına günlük yaşamdan (okul, spor, seyahat) kısa, disleksi dostu bir hikaye yaz. 
       Örn: "Ders 09:15'te başladı ve 40 dakika sürdü. Saat kaçta bitti?"
    2. Eğer varyant 'verbal-match' ise: 'verbalTime' alanına Türkçedeki klasik saat söyleyişini yaz (örn: "Onu yirmi beş geçiyor", "Bire çeyrek var").
    3. Başlangıç Seviyesi: Sadece tam ve yarım saatler.
    4. Orta Seviye: Çeyrek geçe/kala ve 5'in katları.
    5. Zor Seviye: 1 dakikalık hassasiyet ve öğleden sonra/gece (24 saatlik) ayrımı.

    Öğrenci Bağlamı: ${studentContext?.name || 'Öğrenci'} için ilgi çekici senaryolar kullan.
    `;

    const prompt = getMathPrompt("Gelişmiş Zaman Atölyesi", difficulty, rule, studentContext);

    const schema = {
        type: Type.ARRAY,
        items: {
            type: Type.OBJECT,
            properties: {
                title: { type: Type.STRING },
                instruction: { type: Type.STRING },
                pedagogicalNote: { type: Type.STRING },
                variant: { type: Type.STRING },
                clocks: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            id: { type: Type.STRING },
                            hour: { type: Type.INTEGER },
                            minute: { type: Type.INTEGER },
                            timeString: { type: Type.STRING },
                            verbalTime: { type: Type.STRING, nullable: true },
                            options: { type: Type.ARRAY, items: { type: Type.STRING }, nullable: true },
                            answer: { type: Type.STRING },
                            problemText: { type: Type.STRING, nullable: true }
                        },
                        required: ['id', 'hour', 'minute', 'timeString', 'answer']
                    }
                }
            },
            required: ['title', 'instruction', 'clocks']
        }
    };

    const result = await generateWithSchema(prompt, schema, 'gemini-3-flash-preview');
    return result.map((page: any) => ({
        ...page,
        settings: {
            showNumbers: showNumbers !== undefined ? showNumbers : true,
            is24Hour: !!is24Hour,
            showTicks: showTicks !== undefined ? showTicks : true,
            difficulty
        }
    }));
};

