// Fix: Added missing StoryHighlighter export
export const StoryHighlighter: React.FC<{ text: string, highlights?: {text: string, type: string}[] }> = ({ text, highlights = [] }) => {
    let content = text;
    highlights.forEach(h => {
        if (!h.text) return;
        const color = QUESTION_TYPES[h.type]?.color || '#fef3c7';
        content = content.replace(new RegExp(`(${h.text.replace(/[-\/\\^$*+?.()|[\]{}]/g, '\\$&')})`, 'gi'), `<mark style="background-color: ${color}40; border-bottom: 2px solid ${color}" class="rounded-sm px-0.5">$1</mark>`);
    });
    return <div dangerouslySetInnerHTML={{ __html: content.replace(/\n/g, '<br/>') }} />;
};

